// The previous attempt unconditionally asserted
//   assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
// which is NOT a fact in the proof body — it is only the antecedent of the
// implication-shaped ensures clause. Verus rightly rejected those asserts.
//
// Repair: phrase every fact as `assert(H ==> consequence)` so each statement
// is a tautology Verus can discharge by Seq extensionality, then enable the
// vstd array axioms so SMT has the `[A; N]` ext-equality + index axioms in
// scope for the struct-equality step.

broadcast use vstd::array::group_array_axioms;

// (1) Chain both `=~=` ensures-conjuncts through the shared right-hand side
// `pre_self_.seq@.update(i as int, out)` to get `post1.seq@ == post2.seq@`.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
     && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq@ =~= post2_self_.seq@));

assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
     && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq@ == post2_self_.seq@));

// (2) Lift the inner `Seq<A>` equality to `Ghost<Seq<A>>` equality on the
// `seq` field of `Array<A, N>` (Ghost equality is .view() equality).
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
     && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq == post2_self_.seq));

// (3) The inline `Array::view()` form, i.e. `self@ == self.seq@`.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
     && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_@ =~= post2_self_@));

assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
     && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_@ == post2_self_@));

// (4) The unit-typed return is trivially deterministic.
assert(r1 == r2);
